.button {
  background-color: #3b82f6;
  color: white;
  transform: scale(1);

  /* Define on base — applies to both hover-in and hover-out */
  transition:
    background-color 200ms ease,
    transform 200ms cubic-bezier(0.34, 1.56, 0.64, 1);
}

.button:hover {
  background-color: #2563eb;
  transform: scale(1.04);
}

/* Bad: transition on :hover only plays on hover-in, snaps back instantly */
.button:hover {
  transition: background-color 200ms ease; /* DON'T do this */
}

/* Longhand */
.element {
  transition-property: transform, opacity;
  transition-duration: 300ms, 200ms;
  transition-timing-function: ease-out, ease;
  transition-delay: 0ms, 50ms;
}

/* Shorthand — property duration easing delay */
.element {
  transition:
    transform 300ms ease-out 0ms,
    opacity 200ms ease 50ms;
}

/* 'all' — animate all animatable properties (avoid in production) */
.element {
  transition: all 200ms ease; /* risky — animates unintended properties */
}

/* Custom spring-like bounce */
.button:hover {
  transform: scale(1.06);
  transition: transform 400ms cubic-bezier(0.34, 1.56, 0.64, 1);
  /* P1=(0.34,1.56) goes past 1.0 — creates overshoot */
}

/* Discrete steps — sprite frame animation */
.sprite {
  background-position: 0 0;
  transition: background-position 1s steps(8, end);
}
.sprite:hover {
  background-position: -800px 0; /* 8 steps × 100px */
}

/* CSS linear() — multi-point easing (Chrome 113+, Firefox 112+) */
.spring {
  transition: transform 500ms linear(0, 0.5 25%, 1.1 50%, 0.97 75%, 1);
}

/* Good — compositor-only */
.card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgb(0 0 0 / 0.15);
  transition: transform 200ms ease, box-shadow 200ms ease;
}

/* Bad — triggers layout */
.card:hover {
  top: -4px;       /* avoid — layout */
  margin-top: -4px; /* avoid — layout */
}

.animated-element {
  will-change: transform, opacity;
  /* Promotes to its own compositor layer before animation starts */
  /* Removes the cost of the first frame's layer promotion */
}

/* Remove will-change after animation if it's not recurring */
/* Too many will-change elements = high GPU memory usage */

/* from/to — shorthand for 0% and 100% */
@keyframes fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* Multi-stop with stagger */
@keyframes pulse {
  0%, 100% { transform: scale(1);    opacity: 1; }
  50%       { transform: scale(1.05); opacity: 0.8; }
}

/* Combined properties */
@keyframes slide-up {
  from {
    transform: translateY(20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

/* Rotate indefinitely */
@keyframes spin {
  to { transform: rotate(360deg); }
}

/* animation: name duration easing delay iteration direction fill-mode play-state */

.spinner {
  animation: spin 1s linear infinite;
}

.toast {
  animation: slide-up 300ms ease-out both;
  /* 'both' = fill-mode forwards+backwards: keep end state, apply start before delay */
}

/* Delayed entrance — staggered children */
.list-item:nth-child(1) { animation: fade-in 400ms ease-out 0ms  both; }
.list-item:nth-child(2) { animation: fade-in 400ms ease-out 80ms both; }
.list-item:nth-child(3) { animation: fade-in 400ms ease-out 160ms both; }

/* Pause/resume with play-state */
.paused { animation-play-state: paused; }

/* none: element snaps to un-animated state before/after (default) */
.element { animation-fill-mode: none; }

/* forwards: retain the end keyframe after animation completes */
.slide-in { animation: slide-up 400ms ease-out forwards; }

/* backwards: apply start keyframe during delay period */
.delayed  { animation: fade-in 400ms ease-out 200ms backwards; }

/* both: apply backwards during delay AND forwards after completion */
.toast    { animation: slide-up 300ms ease-out 100ms both; }

/* Global reset for motion-sensitive users */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Or handle per-component with a more thoughtful approach */
.card {
  transition: transform 300ms ease;
}

@media (prefers-reduced-motion: reduce) {
  .card {
    transition: opacity 150ms ease;  /* replace motion with a subtle fade */
  }
}

// main.ts — enable animations
import { bootstrapApplication } from '@angular/platform-browser';
import { provideAnimationsAsync } from '@angular/platform-browser/animations/async';

bootstrapApplication(AppComponent, {
  providers: [provideAnimationsAsync()]
});

// notification.component.ts
import {
  trigger, state, style,
  animate, transition
} from '@angular/animations';

@Component({
  selector: 'app-notification',
  animations: [
    trigger('slideIn', [
      transition(':enter', [           // added to DOM
        style({ transform: 'translateY(-100%)', opacity: 0 }),
        animate('300ms ease-out', style({ transform: 'translateY(0)', opacity: 1 })),
      ]),
      transition(':leave', [           // removed from DOM
        animate('200ms ease-in', style({ transform: 'translateY(-100%)', opacity: 0 })),
      ]),
    ]),
  ],
  template: `
    @if (visible()) {
      <div @slideIn class="notification">{{ message() }}</div>
    }
  `
})
export class NotificationComponent {
  visible = signal(false);
  message = signal('');
}

// tooltip.component.ts
@Component({
  template: `
    <button
      (mouseenter)="show.set(true)"
      (mouseleave)="show.set(false)"
    >
      Hover me
      <span class="tooltip" [class.tooltip--visible]="show()">
        Tooltip text
      </span>
    </button>
  `
})
export class TooltipComponent {
  show = signal(false);
}

.tooltip {
  opacity: 0;
  transform: translateY(4px);
  transition: opacity 150ms ease, transform 150ms ease;
  pointer-events: none;
}

.tooltip--visible {
  opacity: 1;
  transform: translateY(0);
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.spinner {
  width: 24px;
  height: 24px;
  border: 3px solid oklch(0.6 0.2 260 / 0.2);
  border-top-color: oklch(0.6 0.2 260);
  border-radius: 50%;
  animation: spin 600ms linear infinite;
}

@media (prefers-reduced-motion: reduce) {
  .spinner {
    animation: none;
    border: 3px solid oklch(0.6 0.2 260);
    /* Static spinner still communicates loading state */
  }
}

@keyframes shimmer {
  from { background-position: -200% 0; }
  to   { background-position: 200% 0; }
}

.skeleton {
  background: linear-gradient(
    90deg,
    #1e293b 25%,
    #334155 50%,
    #1e293b 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
  border-radius: 4px;
}

.skeleton--text {
  height: 1em;
  width: 80%;
  margin-bottom: 0.5em;
}

.skeleton--avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
}

@media (prefers-reduced-motion: reduce) {
  .skeleton {
    animation: none;
    background: #334155;
  }
}

/* HTML: each item gets a --i custom property set inline */
/* <li style="--i: 0"> ... </li> */
/* <li style="--i: 1"> ... </li> */

.list-item {
  animation: fade-slide-up 400ms ease-out both;
  animation-delay: calc(var(--i, 0) * 60ms);
}

@keyframes fade-slide-up {
  from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (prefers-reduced-motion: reduce) {
  .list-item {
    animation: none;
  }
}

// In Angular, set --i in the template
@Component({
  template: `
    <ul>
      @for (item of items(); track item.id; let i = $index) {
        <li class="list-item" [style.--i]="i">{{ item.label }}</li>
      }
    </ul>
  `
})
export class ListComponent {
  items = signal([...]);
}

/* Design token approach */
:root {
  --duration-fast:   100ms;
  --duration-normal: 200ms;
  --duration-slow:   350ms;

  --ease-out:   cubic-bezier(0, 0, 0.2, 1);
  --ease-in:    cubic-bezier(0.4, 0, 1, 1);
  --ease-inout: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
}

.button {
  transition: transform var(--duration-fast) var(--ease-spring);
}

.modal {
  transition:
    opacity var(--duration-normal) var(--ease-out),
    transform var(--duration-slow) var(--ease-out);
}

